var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"오늘은 학회를 소탕하는 작전이라던데? 아디트야 님은 준비를 단단히 하라더군.","JPN":"今日は学会を掃討する作戦を行うそうだぜ？　きっちり準備しておけってアーディティヤ様がおっしゃってたぞ。","ENG":"I heard we'll start the operation to clear out the Society today. Miss Aditya said to prepare well.","TWN":"今天是剿滅學會的作戰吧？阿迪亞說要做好充分準備。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"그 녀석들은 무슨 짓을 벌일지 몰라. 아디트야 님이 명령하는 대로만 행동하라고.\xA0","JPN":"学会は何をしでかすかわからない連中だ。アーディティヤ様の命令通りに動けよ。\xA0","ENG":"You won't know what those bastards will do. So, just do as Miss Aditya orders you, okay?\xA0","TWN":"那些傢伙不知道會耍什麼手段，只要按照阿迪亞的命令行動就好。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"클리파 허수 에너지 밀도가 점점 상승하고 있어. 밖에 나가 있는 사람들이 위험해.","JPN":"クリファ虚数エネルギーの密度が上昇し続けている。くっ、外にいる皆が危険だ。","ENG":"Qlipha Imaginary Energy density is gradually increasing. The people out there are in danger.","TWN":"逆卡巴拉虛數能量密度正在逐漸上升。外面的人很危險。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"아디트야 님께 연락해! 이대로라면……!","JPN":"アーディティヤ様に連絡だ！　このままでは……！","ENG":"Contact Miss Aditya! If this continues...!","TWN":"通知阿迪亞！這樣下去的話……！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"어서 카멜롯에 지원 요청을! 도시 전체가 의식에 휘말린다!","JPN":"急いでキャメロットに支援要請を！　都市全体が儀式に巻き込まれる！","ENG":"Go request backup from Camelot! The entire city is caught up in the ritual!","TWN":"快請求卡梅羅戰隊的支援！整個城市都是儀式範圍！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"새로운 함선에 승선하신 소감이 어떠세요? 아디트야 님?","JPN":"新しい艦船に搭乗した感想はどうですか？　アーディティヤ様？","ENG":"How does it feel to be onboard a new ship, Miss Aditya?","TWN":"登上新艦船的感覺如何？阿迪亞？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"카운터가 된 뒤 갈 곳 없는 저를 받아주셔서 감사합니다. 아디트야 님.","JPN":"カウンターになってから、行く当てのなかった私を迎え入れてくださり、ありがとうございます。アーディティヤ様。","ENG":"Thank you for taking me in when I had no place to go after becoming a Counter, Miss Aditya.","TWN":"謝謝你接納在成為制裁者後無處可去的我，阿迪亞。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"저는 당신에게 구원받았습니다. 부디, 저에게 새 이름을 지어주세요.","JPN":"私はあなたに救われました。どうか、私に新しい名前をつけてください。","ENG":"You saved me. Please, give me a new name.","TWN":"我的命是你就的，請給我一個新的名字吧。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"현실에 침식체가 부상했습니다!","JPN":"現世に侵食体が浮上してきました！","ENG":"A C.O. emerged in the Normalside!","TWN":"現世中有侵蝕體出沒！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"야크샤가 좌표를 전달했습니다. 정화를 준비하겠습니다!","JPN":"ヤクシャーから座標が届きました！　浄化の準備を開始します！","ENG":"Yaksha has sent us the coordinates! Readying the purification!","TWN":"夜叉戰隊已經向我們傳送座標，準備淨化作戰！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"우리는 태양의 빛을 따라!","JPN":"私たちは太陽の光に従って！","ENG":"We follow the light of the sun!","TWN":"我們追隨著太陽的光芒！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아디트야 님, 괜찮으세요?","JPN":"アーディティヤ様、大丈夫ですか？","ENG":"Miss Aditya, are you okay?!","TWN":"阿迪亞，你沒事吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"안색이 많이 안 좋군. 저 침식체, 가만히 우릴 지켜만 보고 있어.","JPN":"顔色が悪いな。それにしてもあの侵食体、じっと俺たちを見つめているぜ。","ENG":"You don't look so good. That C.O. is just watching us.","TWN":"你的臉色不太好。那隻侵蝕體只是在靜靜地看著我們。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"무언가 이상하다.","JPN":"嫌な感じがする……","ENG":"Something's strange.","TWN":"有點不太對勁。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리 전대는 세 명으로 구성되어 있지 않았어.","JPN":"我々の戦隊が三人だけなわけがない。","ENG":"Our division did not consist of just three people.","TWN":"……我們戰隊並不是只有三個人。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"또한 우리만 작전에 투입된 것도 아니지.","JPN":"我々だけが作戦に投入されるのもおかしい。","ENG":"Also, we weren't the only ones to be deployed in the operation.","TWN":"而且不僅僅是我們投入作戰。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"전대가…… 우리 전대가 모두 투입됐어. 하지만…….","JPN":"戦隊が……我々の戦隊は全員投入されたはずだ。しかし……","ENG":"The division... Everyone in our division was deployed. But...","TWN":"戰隊……戰隊的所有人都……但是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그들의 얼굴, 이름…… 그리고 함께했던 기억이 없다.","JPN":"彼らの顔、名前……そして記憶がすべて消えた。","ENG":"Their faces, names... and even the memories we shared with them. I can't remember any of it.","TWN":"他們的長相、名字……以及一起度過的記憶，我一點都想不起來。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"나는 나를 찾아와 이름을 받길 원하는 모든 전대원들의 이름을 지어주고, 기억하고 있었어.","JPN":"私は名付けてほしいと頼んできた、すべての隊員の名前を覚えている。","ENG":"I named and remembered every member of the division who came to me and asked me to give them a name.","TWN":"所有來找我的戰隊員，我都有替他們取名字並且牢牢記住。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만 너희 둘을 포함한 어떤 이도…… 그들을 기억하지 못하고 있다.","JPN":"しかし、君たち2人を含め、誰一人として彼らのことを覚えていない。","ENG":"But I can't remember any of their names... even including you two.","TWN":"但是現在……包括你們兩個人……我誰也不記得。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"그렇다는 것은…….","JPN":"ということは……","ENG":"Which means...","TWN":"那就是說……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};